create table ticketnexus.ticket_impacts_tbl (
    id           number generated by default as identity not null enable,
    code         varchar2(50 char) not null enable,
    display_name varchar2(100 char) not null enable
);

alter table ticketnexus.ticket_impacts_tbl
    add constraint ticket_impacts_pk primary key ( id )
        using index enable;

alter table ticketnexus.ticket_impacts_tbl add constraint ticket_impacts_uk1 unique ( code )
    using index enable;


